"use strict";function t(t){const e=t instanceof Date?t:new Date(t);return`${e.getFullYear()}-${String(e.getMonth()+1).padStart(2,"0")}-${String(e.getDate()).padStart(2,"0")}`}exports.formatDate=t,exports.formatDateTime=function(e){const n=e instanceof Date?e:new Date(e),a=String(n.getHours()).padStart(2,"0"),r=String(n.getMinutes()).padStart(2,"0");return`${t(n)} ${a}:${r}`},exports.isOverdue=function(t){return new Date(t)<new Date},exports.isToday=function(t){const e=new Date(t),n=new Date;return e.getFullYear()===n.getFullYear()&&e.getMonth()===n.getMonth()&&e.getDate()===n.getDate()};
